import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{o as t,c as o,e as i}from"./app.b6fba8d5.js";var n="/immptl/assets/dim_stack_gui.83e8a140.png";const a={},r=i('<h1 id="dimension-stack" tabindex="-1"><a class="header-anchor" href="#dimension-stack" aria-hidden="true">#</a> Dimension Stack</h1><p>Use <a href="./Portals#vertical-dimension-connecting-portal">vertical connecting portals</a> to &quot;stack&quot; the dimensions.</p><p><img src="https://i.loli.net/2021/11/20/aui8vcNer9hAmgJ.png" alt=""></p><p><img src="https://i.loli.net/2021/11/20/r7sUyN6Azm4qiaF.png" alt=""></p><p>You can see the &quot;Dimension Stack&quot; button when creating a new world.</p><p><img src="https://i.loli.net/2021/11/20/helqg7vkcdML5n3.png" alt=""></p><p><img src="'+n+'" alt=""></p><h3 id="main-options" tabindex="-1"><a class="header-anchor" href="#main-options" aria-hidden="true">#</a> Main Options</h3><h4 id="loop" tabindex="-1"><a class="header-anchor" href="#loop" aria-hidden="true">#</a> Loop</h4><p>If enabled, the bottom dimension will connect to the top dimension, creating a vertical world wrapping.</p><h4 id="gravity" tabindex="-1"><a class="header-anchor" href="#gravity" aria-hidden="true">#</a> Gravity</h4><p>If no dimension is flipped, this option will have no effect. The gravity changing functionality requires Gravity Changer (Gravity API) mod.</p><p>This option can be either &quot;Relative to World&quot; or &quot;Relative to View&quot;.</p><ol><li><p>If it&#39;s relative to world, the dimension connecting portal won&#39;t change your gravity. When entering a flipped dimension, your gravity relative to the world will not change <strong>but the &quot;viewing gravity&quot; will change</strong> and a rotation animation will perform. For example, if your gravity is downwards before, then after going into a flipped dimension your gravity will still be the same as the direction that water and lava flows down.</p></li><li><p>If it&#39;s relative to view, the dimension connecting portal will change your gravity. <strong>The &quot;viewing gravity&quot; will not change</strong> and it will not perform rotation animation. For example, if your gravity is downwards before, entering a flipped dimension will make your gravity upwards, which is the opposite of the direction that water and lava flows down, but you will see no &quot;view rotation&quot;.</p></li></ol><p>It&#39;s sometimes confusing that not changing the view gravity means changing the gravity relative to world, and not changing the gravity relative to world means changing the view gravity.</p><h3 id="per-dimension-options" tabindex="-1"><a class="header-anchor" href="#per-dimension-options" aria-hidden="true">#</a> Per-Dimension Options</h3><p>By clicking &quot;Edit&quot; you can edit the selected dimension entry&#39;s options:</p><p><img src="https://s2.loli.net/2021/12/31/9VBFmxTPLn17oRK.png" alt=""></p><h4 id="scale" tabindex="-1"><a class="header-anchor" href="#scale" aria-hidden="true">#</a> Scale</h4><p>This controls the generated portals&#39; scale transformation. The generated connecting portal won&#39;t change the crossing entity&#39;s scale.</p><p>If you want that one block in nether corresponds to 8 blocks in overworld, set the overworld&#39;s scale to 8.</p><p><img src="https://i.loli.net/2021/11/20/ywnkEq6F4pQS7Ha.png" alt=""></p><p>It&#39;s recommended to either <strong>(1)</strong> set the scale between overworld and nether to be 8 or <strong>(2)</strong> set the nether portal mode to be <code>disabled</code>. Because dimension stack does not interfere with how nether portals work, if dimension stack allows player to travel between overworld and nether with 1 by 1 space ratio, and nether portal allows travelling with 1 by 8 space ratio, then the player can easily reach the world border by using two travel methods alternately.</p><h4 id="flipped" tabindex="-1"><a class="header-anchor" href="#flipped" aria-hidden="true">#</a> Flipped</h4><p>Controls the portals&#39; rotating transformation. If enabled, makes the dimension looks &quot;flipped&quot;. Does not change the gravity direction in that dimension (unless you enable gravity change option). If a flipped dimension connects to a non-flipped dimension, the connecting portal will have a 180 degrees rotation transformation along X axis.</p><p><img src="https://i.loli.net/2021/11/20/pXxmBnrQd2CbVIE.png" alt=""></p><h4 id="horizontal-rotation" tabindex="-1"><a class="header-anchor" href="#horizontal-rotation" aria-hidden="true">#</a> Horizontal Rotation</h4><p>Controls the portals&#39; rotating transformation. Make the dimension looks rotated along Y axis.</p><p><img src="https://i.loli.net/2021/11/20/Fnv4GOCW8A3wiJM.png" alt=""></p><h4 id="topy-bottomy" tabindex="-1"><a class="header-anchor" href="#topy-bottomy" aria-hidden="true">#</a> TopY, BottomY</h4><p>Specify the bottom and top Y level of the portal. You can left these two empty by default.</p><p>If Bottom Y is left empty, it will use the dimension type&#39;s <code>min_y</code> property. If Top Y is left empty, it will use the dimension type&#39;s <code>min_y</code> + <code>logical_height</code>.</p><h4 id="bedrock-replacement" tabindex="-1"><a class="header-anchor" href="#bedrock-replacement" aria-hidden="true">#</a> Bedrock Replacement</h4><p>Specify a block that the bedrock will be replaced into. If empty, the bedrock will not be replaced.</p><h3 id="re-configure-dimension-stack-using-the-command" tabindex="-1"><a class="header-anchor" href="#re-configure-dimension-stack-using-the-command" aria-hidden="true">#</a> Re-configure Dimension Stack Using the Command</h3><p>This mod has command <code>/portal dimension_stack</code> (since MC 1.18) that allows re-configuring dimension stack when the world was already created.</p><h3 id="how-to-use-dimension-stack-on-a-server" tabindex="-1"><a class="header-anchor" href="#how-to-use-dimension-stack-on-a-server" aria-hidden="true">#</a> How to Use Dimension Stack on a Server</h3><p>The first method: create a dimension stack world on client and then copy it to the server.</p><p>The second method: use command <code>/portal dimension_stack</code> to enable dimension stack on the server and manually replace existing bedrock blocks into obsidian.</p>',39),s=[r];function l(d,h){return t(),o("div",null,s)}var m=e(a,[["render",l],["__file","Dimension-Stack.html.vue"]]);export{m as default};
